class PaymentLogger {
  final bool enabled;
  final StreamController<PaymentAuditEvent> _controller =
      StreamController.broadcast();

  PaymentLogger({required this.enabled});

  Stream<PaymentAuditEvent> get stream => _controller.stream;

  void log(String name, Map<String, dynamic> payload) {
    if (!enabled) return;
    _controller.add(
      PaymentAuditEvent(
        name: name,
        timestamp: DateTime.now().toUtc(),
        payload: _sanitize(payload),
      ),
    );
  }

  Map<String, dynamic> _sanitize(Map<String, dynamic> source) {
    final result = <String, dynamic>{};
    source.forEach((key, value) {
      final lower = key.toLowerCase();
      if (lower.contains('card') ||
          lower.contains('cvv') ||
          lower.contains('pan') ||
          lower.contains('token') ||
          lower.contains('secret') ||
          lower.contains('receipt')) {
        result[key] = 'REDACTED';
      } else if (value is Map<String, dynamic>) {
        result[key] = _sanitize(value);
      } else {
        result[key] = value;
      }
    });
    return result;
  }

  Future<void> dispose() => _controller.close();
}

class PaymentSecurity {
  static final Random _random = Random.secure();

  static String generateIdempotencyKey() {
    final bytes = List<int>.generate(32, (_) => _random.nextInt(256));
    return base64Url.encode(bytes).replaceAll('=', '');
  }

  static String sha256Hash(String input) {
    return sha256.convert(utf8.encode(input)).toString();
  }

  static Map<String, String> signedHeaders({
    required String body,
    required String secret,
    required String merchantId,
  }) {
    final timestamp = DateTime.now().millisecondsSinceEpoch.toString();
    final signature = sha256Hash('$merchantId.$timestamp.$body.$secret');
    return {
      'X-Merchant-Id': merchantId,
      'X-Signature': signature,
      'X-Timestamp': timestamp,
    };
  }
}

class PaymentHttpClient {
  final PaymentConfig config;
  final PaymentLogger logger;
  final http.Client _client;

  PaymentHttpClient({
    required this.config,
    required this.logger,
    http.Client? client,
  }) : _client = client ?? http.Client();

  Future<Map<String, dynamic>> post(
    String path, {
    required Map<String, dynamic> body,
    Map<String, String> headers = const {},
    String? signingSecret,
  }) async {
    final uri = Uri.parse('${config.apiBaseUrl}$path');
    final encodedBody = jsonEncode(body);

    final mergedHeaders = <String, String>{
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      ...config.defaultHeaders,
      ...headers,
    };

    if (signingSecret != null) {
      mergedHeaders.addAll(
        PaymentSecurity.signedHeaders(
          body: encodedBody,
          secret: signingSecret,
          merchantId: config.merchantId,
        ),
      );
    }

    logger.log('http_request', {
      'method': 'POST',
      'path': path,
      'body': body,
    });

    final response = await _client
        .post(uri, headers: mergedHeaders, body: encodedBody)
        .timeout(config.requestTimeout);

    final responseBody = response.body.isEmpty
        ? <String, dynamic>{}
        : jsonDecode(response.body) as Map<String, dynamic>;

    logger.log('http_response', {
      'path': path,
      'statusCode': response.statusCode,
      'body': responseBody,
    });

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw PaymentException(
        'http_${response.statusCode}',
        responseBody['message']?.toString() ?? 'Gateway request failed',
        responseBody,
      );
    }

    return responseBody;
  }

  Future<void> close() async {
    _client.close();
  }
}

