      },
    );

    return PaymentResult(
      transactionId: response['transactionId']?.toString() ?? transactionId,
      status: PaymentStatus.refunded,
      methodType: PaymentMethodType.wallet,
      gatewayReference: response['gatewayReference']?.toString(),
