  }
}

class InAppPurchaseService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentGatewayService gatewayService;
  final PaymentLogger logger;

  StreamSubscription<List<PurchaseDetails>>? _purchaseSubscription;
  final StreamController<PaymentResult> _purchaseResultController =
      StreamController.broadcast();

  InAppPurchaseService({
    required this.gatewayService,
    required this.logger,
  });

  Stream<PaymentResult> get purchaseResults => _purchaseResultController.stream;

  Future<bool> isAvailable() => _iap.isAvailable();

  Future<List<ProductDetails>> queryProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);
    if (response.error != null) {
      throw PaymentException(
        'iap_query_failed',
        response.error!.message,
        response.error,
      );
    }
    return response.productDetails;
  }

  Future<void> initialize() async {
    _purchaseSubscription ??=
        _iap.purchaseStream.listen(_onPurchaseUpdate, onError: (error) {
      _purchaseResultController.add(
        PaymentResult(
          transactionId: '',
          status: PaymentStatus.failed,
          methodType: PaymentMethodType.inAppPurchase,
          data: {'error': error.toString()},
        ),
      );
    });
  }

  Future<void> buyConsumable(ProductDetails product) async {
    final purchaseParam = PurchaseParam(productDetails: product);
    final started = await _iap.buyConsumable(purchaseParam: purchaseParam);
    if (!started) {
      throw const PaymentException(
        'iap_start_failed',
        'Failed to start consumable purchase',
      );
    }
  }

  Future<void> buyNonConsumable(ProductDetails product) async {
    final purchaseParam = PurchaseParam(productDetails: product);
    final started = await _iap.buyNonConsumable(purchaseParam: purchaseParam);
    if (!started) {
      throw const PaymentException(
        'iap_start_failed',
        'Failed to start non-consumable purchase',
      );
    }
  }

  Future<void> restorePurchases() => _iap.restorePurchases();

  Future<void> _onPurchaseUpdate(List<PurchaseDetails> purchases) async {
    for (final purchase in purchases) {
      try {
        logger.log('iap_purchase_update', {
          'productId': purchase.productID,
          'purchaseId': purchase.purchaseID,
          'status': purchase.status.name,
        });

        switch (purchase.status) {
          case PurchaseStatus.pending:
            _purchaseResultController.add(
              PaymentResult(
                transactionId: purchase.purchaseID ?? '',
                status: PaymentStatus.pending,
                methodType: PaymentMethodType.inAppPurchase,
                data: {'productId': purchase.productID},
              ),
            );
            break;
          case PurchaseStatus.error:
            _purchaseResultController.add(
              PaymentResult(
                transactionId: purchase.purchaseID ?? '',
                status: PaymentStatus.failed,
                methodType: PaymentMethodType.inAppPurchase,
                data: {
                  'productId': purchase.productID,
                  'error': purchase.error?.message,
                },
              ),
            );
            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
            break;
          case PurchaseStatus.purchased:
          case PurchaseStatus.restored:
            final verification = await gatewayService.verifyInAppPurchase(
              source: Platform.isIOS ? 'ios' : 'android',
              productId: purchase.productID,
              transactionId: purchase.purchaseID ?? '',
              receiptData: purchase.verificationData.serverVerificationData,
            );

            _purchaseResultController.add(
              verification.copyWith(
                status: purchase.status == PurchaseStatus.restored
                    ? PaymentStatus.restored
                    : verification.status,
                data: {
                  ...verification.data,
                  'productId': purchase.productID,
                },
              ),
            );

            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
            break;
          case PurchaseStatus.canceled:
            _purchaseResultController.add(
              PaymentResult(
                transactionId: purchase.purchaseID ?? '',
                status: PaymentStatus.cancelled,
                methodType: PaymentMethodType.inAppPurchase,
                data: {'productId': purchase.productID},
              ),
            );
            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
            break;
        }
      } catch (e) {
        _purchaseResultController.add(
          PaymentResult(
            transactionId: purchase.purchaseID ?? '',
            status: PaymentStatus.failed,
            methodType: PaymentMethodType.inAppPurchase,
            data: {
              'productId': purchase.productID,
              'error': e.toString(),
            },
          ),
        );
      }
    }
  }

  Future<void> dispose() async {
    await _purchaseSubscription?.cancel();
    await _purchaseResultController.close();
  }
}

class MobileWalletService {
  final PaymentConfig config;
  final WalletBridge walletBridge;
  final PaymentGatewayService gatewayService;
  final PaymentLogger logger;

  MobileWalletService({
    required this.config,
    required this.walletBridge,
    required this.gatewayService,
    required this.logger,
  });

  Future<bool> isAvailable() async {
    if (Platform.isIOS) return walletBridge.isApplePayAvailable();
    if (Platform.isAndroid) return walletBridge.isGooglePayAvailable();
    return false;
  }

  Future<PaymentResult> payWithNativeWallet(WalletPaymentRequest request) async {
    if (Platform.isIOS) {
      return _payWithApplePay(request);
    } else if (Platform.isAndroid) {
      return _payWithGooglePay(request);
    }
    throw const PaymentException(
      'unsupported_platform',
      'Wallet payments are only supported on iOS and Android',
    );
  }

  Future<PaymentResult> _payWithApplePay(WalletPaymentRequest request) async {
    final tokenResponse = await walletBridge.presentApplePay(
      request: {
        'merchantId': config.applePayMerchantId,
        'countryCode': request.countryCode,
        'currencyCode': request.currencyCode,
        'amountMinor': request.amountMinor,
        'label': request.label,
      },
    );

    final gatewayResult = await gatewayService.processWalletPayment(
      WalletPaymentRequest(
        idempotencyKey: request.idempotencyKey,
        currencyCode: request.currencyCode,
        amountMinor: request.amountMinor,
        countryCode: request.countryCode,
        label: request.label,
        customerId: request.customerId,
        billingDetails: request.billingDetails,
        shippingDetails: request.shippingDetails,
        metadata: {
          ...request.metadata,
          'platform': 'ios',
          'walletType': 'apple_pay',
          'walletPayload': tokenResponse,
        },
      ),
    );

    return gatewayResult.copyWith(methodType: PaymentMethodType.applePay);
  }

  Future<PaymentResult> _payWithGooglePay(WalletPaymentRequest request) async {
    final tokenResponse = await walletBridge.presentGooglePay(
      request: {
        'gateway': config.googlePayGatewayName,
        'merchantId': config.merchantId,
        'countryCode': request.countryCode,
        'currencyCode': request.currencyCode,
        'amountMinor': request.amountMinor,
        'label': request.label,
      },
    );

    final gatewayResult = await gatewayService.processWalletPayment(
      WalletPaymentRequest(
        idempotencyKey: request.idempotencyKey,
        currencyCode: request.currencyCode,
        amountMinor: request.amountMinor,
        countryCode: request.countryCode,
        label: request.label,
        customerId: request.customerId,
        billingDetails: request.billingDetails,
        shippingDetails: request.shippingDetails,
        metadata: {
          ...request.metadata,
          'platform': 'android',
          'walletType': 'google_pay',
          'walletPayload': tokenResponse,
        },
      ),
    );

    return gatewayResult.copyWith(methodType: PaymentMethodType.googlePay);
  }
}

class PaymentRepository {
  final PaymentConfig config;
  final PaymentLogger logger;
  final PaymentHttpClient httpClient;
  late final PaymentGatewayService gatewayService;
  late final InAppPurchaseService inAppPurchaseService;
  late final MobileWalletService mobileWalletService;

  PaymentRepository._({
    required this.config,
    required this.logger,
    required this.httpClient,
  }) {
    gatewayService = PaymentGatewayService(
      config: config,
      httpClient: httpClient,
      logger: logger,
    );
    inAppPurchaseService = InAppPurchaseService(
      gatewayService: gatewayService,
      logger: logger,
    );
    mobileWalletService = MobileWalletService(
      config: config,
      walletBridge: WalletBridge(),
      gatewayService: gatewayService,
      logger: logger,
    );
  }

  factory PaymentRepository(PaymentConfig config) {
    final logger = PaymentLogger(enabled: config.enableLogs);
    final client = PaymentHttpClient(config: config, logger: logger);
    return PaymentRepository._(
      config: config,
      logger: logger,
      httpClient: client,
    );
  }

  Future<void> initialize() async {
    await inAppPurchaseService.initialize();
    logger.log('payment_repository_initialized', {
      'environment': config.environment.name,
      'provider': config.gatewayProvider.name,
    });
  }

  Future<List<ProductDetails>> loadProducts() {
    return inAppPurchaseService.queryProducts(config.productIds);
  }

  Future<void> purchaseConsumable(ProductDetails product) {
    return inAppPurchaseService.buyConsumable(product);
  }

  Future<void> purchaseNonConsumable(ProductDetails product) {
    return inAppPurchaseService.buyNonConsumable(product);
  }

  Stream<PaymentResult> get inAppPurchaseResults =>
      inAppPurchaseService.purchaseResults;

  Future<PaymentResult> payWithWallet({
    required int amountMinor,
    required String currencyCode,
    required String countryCode,
    required String label,
    required String customerId,
    Map<String, dynamic> billingDetails = const {},
    Map<String, dynamic> shippingDetails = const {},
    Map<String, dynamic> metadata = const {},
  }) {
    return mobileWalletService.payWithNativeWallet(
      WalletPaymentRequest(
        idempotencyKey: PaymentSecurity.generateIdempotencyKey(),
        currencyCode: currencyCode,
        amountMinor: amountMinor,
        countryCode: countryCode,
        label: label,
        customerId: customerId,
        billingDetails: billingDetails,
        shippingDetails: shippingDetails,
        metadata: metadata,
      ),
    );
  }

  Future<PaymentResult> payWithTokenizedCard({
    required int amountMinor,
    required String currencyCode,
    required String paymentMethodToken,
    required String customerId,
    Map<String, dynamic> metadata = const {},
  }) {
    return gatewayService.processTokenizedCard(
      TokenizedCardRequest(
        idempotencyKey: PaymentSecurity.generateIdempotencyKey(),
        amountMinor: amountMinor,
        currencyCode: currencyCode,
        paymentMethodToken: paymentMethodToken,
        customerId: customerId,
        metadata: metadata,
      ),
    );
  }

  Future<PaymentResult> refund({
    required String transactionId,
    required int amountMinor,
    required String reason,
  }) {
    return gatewayService.refund(
      transactionId: transactionId,
      amountMinor: amountMinor,
      reason: reason,
    );
  }

  Future<void> dispose() async {
    await inAppPurchaseService.dispose();
    await httpClient.close();
    await logger.dispose();
  }
}

class PciCompliancePolicy {
  final bool tokenizationOnly;
  final bool noSensitiveStorage;
  final bool tlsRequired;
  final bool auditLoggingEnabled;
  final bool backendReceiptValidationRequired;

  const PciCompliancePolicy({
    this.tokenizationOnly = true,
    this.noSensitiveStorage = true,
    this.tlsRequired = true,
    this.auditLoggingEnabled = true,
    this.backendReceiptValidationRequired = true,
  });

  void validate(PaymentConfig config) {
    if (tlsRequired && !config.apiBaseUrl.startsWith('https://')) {
      throw const PaymentException(
        'pci_non_tls_endpoint',
        'PCI compliance requires HTTPS endpoints',
      );
    }
    if (auditLoggingEnabled && !config.enableLogs) {
      debugPrint(
        'Warning: audit logging is disabled. Enable logs for compliance traceability.',
      );
    }
  }
}

class PaymentModule {
  final PaymentRepository repository;
  final PciCompliancePolicy pciPolicy;

  PaymentModule._({
    required this.repository,
    required this.pciPolicy,
  });

  static Future<PaymentModule> create({
    required PaymentConfig config,
    PciCompliancePolicy pciPolicy = const PciCompliancePolicy(),
  }) async {
    pciPolicy.validate(config);
    final repository = PaymentRepository(config);
    await repository.initialize();
    return PaymentModule._(
      repository: repository,
      pciPolicy: pciPolicy,
    );
  }

  Stream<PaymentAuditEvent> get auditEvents => repository.logger.stream;

  Stream<PaymentResult> get inAppPurchaseResults =>
      repository.inAppPurchaseResults;

  Future<List<ProductDetails>> getProducts() => repository.loadProducts();

  Future<void> buyConsumable(ProductDetails product) =>
      repository.purchaseConsumable(product);

  Future<void> buyNonConsumable(ProductDetails product) =>
      repository.purchaseNonConsumable(product);

  Future<PaymentResult> payWithWallet({
    required int amountMinor,
    required String currencyCode,
    required String countryCode,
    required String label,
    required String customerId,
    Map<String, dynamic> billingDetails = const {},
    Map<String, dynamic> shippingDetails = const {},
    Map<String, dynamic> metadata = const {},
  }) {
    return repository.payWithWallet(
      amountMinor: amountMinor,
      currencyCode: currencyCode,
      countryCode: countryCode,
      label: label,
      customerId: customerId,
      billingDetails: billingDetails,
      shippingDetails: shippingDetails,
      metadata: metadata,
    );
  }

  Future<PaymentResult> payWithTokenizedCard({
    required int amountMinor,
    required String currencyCode,
    required String paymentMethodToken,
    required String customerId,
    Map<String, dynamic> metadata = const {},
  }) {
    return repository.payWithTokenizedCard(
      amountMinor: amountMinor,
      currencyCode: currencyCode,
      paymentMethodToken: paymentMethodToken,
      customerId: customerId,
      metadata: metadata,
    );
  }

  Future<PaymentResult> refund({
    required String transactionId,
    required int amountMinor,
    required String reason,
  }) {
    return repository.refund(
      transactionId: transactionId,
      amountMinor: amountMinor,
      reason: reason,
    );
  }

  Future<void> dispose() => repository.dispose();
}

